// Prepare the Cypher query for execution
const input = $input.first().json.body;

const query = input.query || input.cypher || '';
const mode = input.mode || 'read';
const returnFormat = input.format || 'json';

// Validate query safety
const isWriteQuery = /\b(CREATE|MERGE|DELETE|SET|REMOVE|DETACH)\b/i.test(query);
const isSafeRead = /^\s*(MATCH|OPTIONAL MATCH|CALL|RETURN|WITH)/i.test(query);

if (mode === 'read' && isWriteQuery) {
  throw new Error('Write operations not allowed in read mode');
}

return {
  json: {
    query: query.trim(),
    mode: mode,
    isWriteQuery: isWriteQuery,
    returnFormat: returnFormat,
    timestamp: new Date().toISOString()
  }
};

// Parse Neo4j HTTP response into clean format
const response = $input.first().json;
const inputData = $('2. Validate & Prepare Query').first().json;

let results = [];
let columns = [];
let error = null;
let rowCount = 0;

try {
  const body = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;

  if (body.errors && body.errors.length > 0) {
    error = body.errors.map(e => e.message).join('; ');
  }

  if (body.results && body.results[0]) {
    const result = body.results[0];
    columns = result.columns || [];

    if (result.data) {
      results = result.data.map(d => {
        // Convert row array to object using column names
        const obj = {};
        columns.forEach((col, i) => {
          obj[col] = d.row[i];
        });
        return obj;
      });
      rowCount = results.length;
    }
  }
} catch (e) {
  error = 'Failed to parse Neo4j response: ' + e.message;
}

return {
  json: {
    success: !error,
    query: inputData.query,
    mode: inputData.mode,
    columns: columns,
    rowCount: rowCount,
    results: results,
    error: error,
    executedAt: new Date().toISOString()
  }
};
